DROP TABLE IF EXISTS `demandes_conge`;
/*!40101 SET @saved_cs_client     = @@character_set_client */;
/*!40101 SET character_set_client = utf8 */;
CREATE TABLE `demandes_conge` (
  `id` int(11) NOT NULL AUTO_INCREMENT,
  `matricule` varchar(20) NOT NULL,
  `nom_complet` varchar(150) NOT NULL,
  `cin` varchar(20) NOT NULL,
  `poste` varchar(100) DEFAULT NULL,
  `adresse` text DEFAULT NULL,
  `date_debut` date NOT NULL,
  `date_fin` date NOT NULL,
  `cause` text NOT NULL,
  `statut` enum('validé','refusé') DEFAULT NULL,
  `date_demande` timestamp NOT NULL DEFAULT current_timestamp(),
  `date_validation` datetime DEFAULT NULL,
  PRIMARY KEY (`id`),
  KEY `fk_user_matricule` (`matricule`),
  CONSTRAINT `fk_user_matricule` FOREIGN KEY (`matricule`) REFERENCES `utilisateur` (`matricule`) ON UPDATE CASCADE
) ENGINE=InnoDB AUTO_INCREMENT=28 DEFAULT CHARSET=utf8mb4 COLLATE=utf8mb4_general_ci;
